import { orders, products, getNextOrderId } from "../data.js";
import type { CreateOrderInput, Order, OrderItem } from "../types.js";
import { ServiceError } from "./errors.js";

export { ServiceError };

// ── Filter types ──────────────────────────────────────────────────────────────

export interface OrderFilters {
  userId?: number;
  status?: string;
}

// ── Return types ──────────────────────────────────────────────────────────────

export interface OrderSummary {
  count: number;
  totalRevenue: number;
}

export interface OrderListResult {
  orders: Order[];
  summary: OrderSummary;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

// ── Constants ─────────────────────────────────────────────────────────────────

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"] as const;

const VALID_TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

// ── Service functions ─────────────────────────────────────────────────────────

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrder(id: number): EnrichedOrder {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new ServiceError("Order not found", 404);
  }

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return { ...order, items: enrichedItems };
}

export function createOrder(input: CreateOrderInput): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError("userId and items are required", 400);
  }

  if (input.items.length === 0) {
    throw new ServiceError("Order must have at least one item", 400);
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);

    if (!product) {
      throw new ServiceError(`Product ${item.productId} not found`, 400);
    }

    if (item.quantity <= 0) {
      throw new ServiceError("Quantity must be positive", 400);
    }

    if (product.stock < item.quantity) {
      throw new ServiceError(`Insufficient stock for ${product.name}`, 400);
    }

    product.stock -= item.quantity;
    total += product.price * item.quantity;

    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(id: number, status: string): Order {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new ServiceError("Order not found", 404);
  }

  if (!VALID_STATUSES.includes(status as (typeof VALID_STATUSES)[number])) {
    throw new ServiceError(
      `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`,
      400,
    );
  }

  if (!VALID_TRANSITIONS[order.status]?.includes(status)) {
    throw new ServiceError(
      `Cannot transition from ${order.status} to ${status}`,
      400,
    );
  }

  order.status = status as Order["status"];

  return order;
}

